section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/design-qa-during-build.json",
  "title": "Design QA During Build",
  "type": "object",
  "required": [
    "artefact_id",
    "sprint_id",
    "build_ref",
    "screens_audited",
    "drift_count",
    "deviation_log",
    "fix_tickets",
    "signed_off_by",
    "remaining_open",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "sprint_id": {
      "type": "string",
      "description": "sprint_id",
      "minLength": 1
    },
    "build_ref": {
      "type": "string",
      "description": "build_ref",
      "minLength": 1
    },
    "screens_audited": {
      "type": "array",
      "description": "screens_audited (array)",
      "minItems": 1
    },
    "drift_count": {
      "type": "number",
      "description": "drift_count (numeric)"
    },
    "deviation_log": {
      "type": "array",
      "description": "deviation_log (array)",
      "minItems": 1
    },
    "fix_tickets": {
      "type": "array",
      "description": "fix_tickets (array)",
      "minItems": 1
    },
    "signed_off_by": {
      "type": "string",
      "description": "signed_off_by",
      "minLength": 1
    },
    "remaining_open": {
      "type": "array",
      "description": "remaining_open (array)",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
